  1→@import 'tailwindcss';
  2→
  3→/* Self-hosted Inter font - eliminates Google Fonts round-trips for faster FCP */
  4→@font-face {
  5→    font-family: 'Inter';
  6→    font-style: normal;
  7→    font-weight: 100 900;
  8→    font-display: swap;
  9→    src: url('/fonts/inter-latin-variable.woff2') format('woff2');
 10→    unicode-range:
 11→        U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F,
 12→        U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
 13→}
 14→
 15→/* CSS-first Tailwind v4 configuration */
 16→@theme {
 17→    /* Colors - Warm dark palette */
 18→    --color-background: #14130f;
 19→    --color-surface: #1a1917;
 20→    --color-surface-elevated: #222120;
 21→    --color-border: #2e2d2a;
 22→    --color-border-subtle: #24231f;
 23→
 24→    --color-text-primary: #fafafa;
 25→    --color-text-secondary: #a1a1aa;
 26→    --color-text-tertiary: #9e9ea8;
 27→
 28→    /* Accent - mustard yellow (use dark text on buttons for accessibility) */
 29→    --color-accent: #ffc206;
 30→    --color-accent-hover: #ffd23f;
 31→    --color-accent-glow: rgba(255, 194, 6, 0.4);
 32→    --color-accent-contrast: #14130f;
 33→
 34→    /* Semantic colors */
 35→    --color-warning: #ff4d6d;
 36→
 37→    /* Fonts - Inter is self-hosted, monospace falls back to system */
 38→    --font-sans: 'Inter', system-ui, -apple-system, sans-serif;
 39→    --font-mono: ui-monospace, 'SFMono-Regular', Menlo, Monaco, Consolas, monospace;
 40→
 41→    /* Spacing */
 42→    --spacing-section: 8rem;
 43→
 44→    /* Animation */
 45→    --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
 46→    --duration-normal: 300ms;
 47→    --duration-slow: 500ms;
 48→}
 49→
 50→/* Global styles */
 51→html {
 52→    scroll-behavior: smooth;
 53→}
 54→
 55→body {
 56→    background-color: var(--color-background);
 57→    color: var(--color-text-primary);
 58→    font-family: var(--font-sans) sans-serif;
 59→    -webkit-font-smoothing: antialiased;
 60→    -moz-osx-font-smoothing: grayscale;
 61→    overflow-x: hidden;
 62→}
 63→
 64→/* Hide newsletter elements before JS hydration if user already subscribed/dismissed */
 65→.newsletter-hidden [data-newsletter-nav] {
 66→    display: none;
 67→}
 68→
 69→/* Selection */
 70→::selection {
 71→    background-color: var(--color-accent);
 72→    color: var(--color-accent-contrast);
 73→}
 74→
 75→/* Gradient text utility */
 76→.gradient-text {
 77→    background: linear-gradient(135deg, #fff 0%, #a1a1aa 100%);
 78→    -webkit-background-clip: text;
 79→    background-clip: text;
 80→    -webkit-text-fill-color: transparent;
 81→}
 82→
 83→/* Shiki dual theme: default to dark, switch to light via prefers-color-scheme.
 84→   Blog code blocks override this to stay dark (see blog-prose.css). */
 85→.astro-code,
 86→.astro-code span {
 87→    color: var(--shiki-dark) !important;
 88→    background-color: var(--shiki-dark-bg) !important;
 89→    font-style: var(--shiki-dark-font-style) !important;
 90→    font-weight: var(--shiki-dark-font-weight) !important;
 91→    text-decoration: var(--shiki-dark-text-decoration) !important;
 92→}
 93→
 94→@media (prefers-color-scheme: light) {
 95→    :root:not([data-force-dark]) .astro-code,
 96→    :root:not([data-force-dark]) .astro-code span {
 97→        color: var(--shiki-light) !important;
 98→        background-color: var(--shiki-light-bg) !important;
 99→        font-style: var(--shiki-light-font-style) !important;
100→        font-weight: var(--shiki-light-font-weight) !important;
101→        text-decoration: var(--shiki-light-text-decoration) !important;
102→    }
103→}
104→
105→/* Glow effect */
106→.glow {
107→    box-shadow: 0 0 40px var(--color-accent-glow);
108→}
109→
110→/* Fade in animation - GPU optimized to avoid layout shifts */
111→@keyframes fade-in-up {
112→    from {
113→        opacity: 0;
114→        transform: translateY(20px);
115→    }
116→
117→    to {
118→        opacity: 1;
119→        transform: translateY(0);
120→    }
121→}
122→
123→.animate-fade-in-up {
124→    animation: fade-in-up var(--duration-slow) var(--ease-out-expo) forwards;
125→    will-change: opacity, transform;
126→    contain: layout style;
127→}
128→
129→/* Blur in animation - Modern entrance */
130→@keyframes blur-in {
131→    from {
132→        opacity: 0;
133→        filter: blur(10px);
134→        transform: translateY(10px);
135→    }
136→
137→    to {
138→        opacity: 1;
139→        filter: blur(0);
140→        transform: translateY(0);
141→    }
142→}
143→
144→.animate-blur-in {
145→    animation: blur-in 1s cubic-bezier(0.16, 1, 0.3, 1) both;
146→}
147→
148→/* Stagger delays */
149→.delay-100 {
150→    animation-delay: 100ms;
151→}
152→
153→.delay-200 {
154→    animation-delay: 200ms;
155→}
156→
157→.delay-300 {
158→    animation-delay: 300ms;
159→}
160→
161→.delay-400 {
162→    animation-delay: 400ms;
163→}
164→
165→/* Light mode tokens for sub-pages (landing page overrides to stay dark) */
166→@media (prefers-color-scheme: light) {
167→    :root:not([data-force-dark]) {
168→        --color-background: #fafaf8;
169→        --color-surface: #f0efec;
170→        --color-surface-elevated: #e8e7e3;
171→        --color-border: #d8d7d3;
172→        --color-border-subtle: #e2e1dd;
173→
174→        --color-text-primary: #1a1917;
175→        --color-text-secondary: #5c5c66;
176→        --color-text-tertiary: #84848e;
177→
178→        --color-accent: #d4a006;
179→        --color-accent-hover: #b8900a;
180→        --color-accent-glow: rgba(212, 160, 6, 0.25);
181→        --color-accent-contrast: #14130f;
182→
183→        --color-warning: #d4365c;
184→    }
185→}
186→
187→/* Reduced motion: disable decorative hover scale effects, keep color transitions */
188→@media (prefers-reduced-motion: reduce) {
189→    html {
190→        scroll-behavior: auto;
191→    }
192→
193→    .animate-fade-in-up {
194→        animation: none;
195→        opacity: 1;
196→        transform: none;
197→    }
198→}
