---
import DownloadButton from './DownloadButton.astro'
---

<section class="hero-section relative overflow-hidden px-6 pt-16 md:px-12 lg:px-20">
    <!-- Background gradient -->
    <div
        class="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_80%_50%_at_50%_-20%,rgba(255,194,6,0.15),transparent)]"
    >
    </div>

    <!-- Grid pattern overlay -->
    <div
        class="pointer-events-none absolute inset-0 bg-[linear-gradient(var(--color-border-subtle)_1px,transparent_1px),linear-gradient(90deg,var(--color-border-subtle)_1px,transparent_1px)] bg-[size:4rem_4rem] [mask-image:radial-gradient(ellipse_60%_60%_at_50%_50%,black,transparent)]"
    >
    </div>

    <div class="hero-content relative z-10 pt-16 text-left md:pt-24">
        <!-- Badge - Step 1 -->
        <div
            class="animate-blur-in stagger-1 mb-8 inline-flex items-center gap-2 rounded-full border border-[var(--color-border)] bg-[var(--color-surface)] px-4 py-1.5"
        >
            <span class="h-2 w-2 animate-pulse rounded-full bg-[var(--color-accent)]"></span>
            <span class="text-sm text-[var(--color-text-secondary)]">With on-device AI</span>
        </div>

        <!-- Headline - Steps 2 & 3 -->
        <h1 class="mb-6 text-3xl font-bold leading-tight tracking-tight md:text-4xl lg:text-6xl">
            <span class="animate-blur-in stagger-2 inline-block">Every folder sized.</span>
            <span class="animate-blur-in stagger-3 inline-block gradient-text">Every file found.</span>
        </h1>

        <!-- Subheadline - Step 4 -->
        <p class="animate-blur-in stagger-4 mb-10 max-w-xl text-lg text-[var(--color-text-secondary)] md:text-xl">
            Indexes your entire drive in minutes. Directory sizes everywhere, instant search, keyboard-driven
            everything. Built in Rust, free for personal use.
        </p>

        <!-- CTA Buttons - Steps 5 & 6 -->
        <div class="flex flex-col items-start gap-4 sm:flex-row sm:items-stretch">
            <DownloadButton variant="hero" class="animate-blur-in stagger-5 w-full sm:w-auto" />
            <a
                href="https://github.com/vdavid/cmdr"
                target="_blank"
                rel="noopener noreferrer"
                class="animate-blur-in stagger-6 inline-flex w-full items-center justify-center gap-2 rounded-xl border border-[var(--color-border)] bg-[var(--color-surface)] px-8 py-4 text-lg font-semibold transition-all duration-300 hover:border-[var(--color-text-tertiary)] hover:bg-[var(--color-surface-elevated)] sm:w-auto sm:justify-start"
            >
                <svg class="h-5 w-5" fill="currentColor" viewBox="0 0 24 24" aria-hidden="true">
                    <path
                        d="M12 0c-6.626 0-12 5.373-12 12 0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23.957-.266 1.983-.399 3.003-.404 1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576 4.765-1.589 8.199-6.086 8.199-11.386 0-6.627-5.373-12-12-12z"
                    ></path>
                </svg>
                View source
            </a>
        </div>

        <!-- Pricing hint - Step 7 -->
        <p class="animate-blur-in stagger-7 mt-8 text-sm text-[var(--color-text-tertiary)]">
            Source-available · Free forever for personal use · Commercial from $59/year
        </p>
    </div>

    <!-- Hero illustration with 3D perspective -->
    <div class="hero-illustration" aria-hidden="true">
        <div class="hero-perspective">
            <div class="hero-base">
                <!-- Frame (always visible) -->
                <img src="/hero/cmdr-hero-frame-dark.png" alt="" class="hero-layer hero-frame" />
                <!-- Right pane (animates in first) -->
                <img src="/hero/cmdr-hero-right-pane-dark.png" alt="" class="hero-layer hero-right-pane" />
                <!-- Left pane (animates in second) -->
                <img src="/hero/cmdr-hero-left-pane-dark.png" alt="" class="hero-layer hero-left-pane" />
            </div>
        </div>
    </div>
</section>

<style>
    /* Text blur-in animation - global so it applies to classes */
    :global(.animate-blur-in) {
        animation: blur-in 1s cubic-bezier(0.16, 1, 0.3, 1) both;
    }

    /* Stagger delays for 7-step animation (100ms apart, overlapping) */
    :global(.stagger-1) {
        animation-delay: 0ms;
    }
    :global(.stagger-2) {
        animation-delay: 100ms;
    }
    :global(.stagger-3) {
        animation-delay: 200ms;
    }
    :global(.stagger-4) {
        animation-delay: 300ms;
    }
    :global(.stagger-5) {
        animation-delay: 400ms;
    }
    :global(.stagger-6) {
        animation-delay: 500ms;
    }
    :global(.stagger-7) {
        animation-delay: 600ms;
    }

    @keyframes blur-in {
        from {
            opacity: 0;
            filter: blur(10px);
            transform: translateY(10px);
        }
        to {
            opacity: 1;
            filter: blur(0);
            transform: translateY(0);
        }
    }

    .hero-section {
        min-height: 100vh;
        position: relative;
    }

    /* Gradient overlay at bottom - covers full width including padding */
    .hero-section::after {
        content: '';
        pointer-events: none;
        z-index: 5;
        background: linear-gradient(to bottom, transparent 50%, var(--color-background) 100%);
        position: absolute;
        inset: 0;
    }

    .hero-content {
        position: relative;
        z-index: 10;
    }

    .hero-illustration {
        pointer-events: none;
        user-select: none;
        width: 100%;
        position: relative;
        margin-top: -200px;
        margin-left: -100px;
    }

    @media (max-width: 767px) {
        .hero-illustration {
            height: 600px;
            margin-top: 0;
            margin-left: -40px;
        }
    }

    .hero-perspective {
        perspective: 4000px;
        perspective-origin: 100% 0;
    }

    .hero-base {
        transform-origin: 0 0;
        backface-visibility: hidden;
        width: 1600px;
        height: 900px;
        margin: 280px auto auto;
        position: absolute;
        top: 0;
        bottom: 0;
        left: -100px;
        right: 0;
        transform: translate(2%) scale(1.2) rotateX(47deg) rotateY(31deg) rotate(324deg);
    }

    @media (max-width: 767px) {
        .hero-base {
            margin-top: 100px;
            margin-left: 1%;
            transform: scale(0.7) rotateX(47deg) rotateY(21deg) rotate(330deg);
        }
    }

    /* Scale hero image on large screens */
    @media (min-width: 1700px) {
        .hero-base {
            width: 94vw;
            height: calc(94vw * 9 / 16);
        }
    }

    .hero-layer {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        object-fit: contain;
    }

    /* Gradient fade on right edge - more aggressive to avoid cutoff */
    .hero-frame,
    .hero-left-pane,
    .hero-right-pane {
        mask-image: linear-gradient(to right, black 0%, black 50%, transparent 80%);
    }

    /* Frame - visible immediately with subtle blur-in */
    .hero-frame {
        opacity: 0;
        animation: hero-image-in 1.5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    }

    /* Right pane - animates in first (blur + translate) */
    .hero-right-pane {
        opacity: 0;
        animation: hero-image-in 2s cubic-bezier(0.16, 1, 0.3, 1) 0.3s forwards;
    }

    /* Left pane - animates in second */
    .hero-left-pane {
        opacity: 0;
        animation: hero-image-in 2s cubic-bezier(0.16, 1, 0.3, 1) 1s forwards;
    }

    @keyframes hero-image-in {
        0% {
            opacity: 0;
            filter: blur(10px);
            transform: translate(165%, 200%);
        }
        100% {
            opacity: 1;
            filter: none;
            transform: none;
        }
    }

    /* Degrade to opacity-only fade under reduced motion */
    @keyframes fade-in-only {
        from {
            opacity: 0;
        }
        to {
            opacity: 1;
        }
    }

    @media (prefers-reduced-motion: reduce) {
        :global(.animate-blur-in) {
            animation: fade-in-only 0.5s ease both;
            filter: none;
            transform: none;
        }

        .hero-frame,
        .hero-right-pane,
        .hero-left-pane {
            animation: fade-in-only 0.8s ease both;
            filter: none;
            transform: none;
        }
    }
</style>

