327→    document.addEventListener('astro:page-load', () => {
328→        // Check if newsletter should be hidden site-wide
329→        const newsletterHidden =
330→            localStorage.getItem('newsletter-subscribed') === 'true' ||
331→            localStorage.getItem('newsletter-dismissed') === 'true' ||
332→            localStorage.getItem('newsletter-cta-dismissed') === 'true'
333→
334→        // Desktop newsletter toggle
335→        const desktopToggle = document.querySelector<HTMLButtonElement>('[data-newsletter-toggle]')
336→        const newsletterPanel = document.getElementById('newsletter-panel')
337→
338→        if (newsletterHidden) {
339→            // Hide all newsletter nav elements
340→            document.querySelectorAll<HTMLElement>('[data-newsletter-nav]').forEach((el) => {
341→                el.style.display = 'none'
342→            })
343→            // Close the panel if it's open
344→            if (newsletterPanel && newsletterPanel.getAttribute('aria-hidden') === 'false') {
345→                newsletterPanel.setAttribute('aria-hidden', 'true')
346→                if (desktopToggle) desktopToggle.setAttribute('aria-expanded', 'false')
347→            }
348→        }
349→
350→        if (desktopToggle && newsletterPanel && !newsletterHidden) {
351→            if (!desktopToggle.dataset.bound) {
352→                desktopToggle.dataset.bound = 'true'
353→
354→                const openNewsletter = () => {
355→                    newsletterPanel.setAttribute('aria-hidden', 'false')
356→                    desktopToggle.setAttribute('aria-expanded', 'true')
357→                    const emailInput = newsletterPanel.querySelector<HTMLInputElement>('input[type="email"]')
358→                    setTimeout(() => emailInput?.focus(), 50)
359→                }
360→
361→                const closeNewsletter = () => {
362→                    newsletterPanel.setAttribute('aria-hidden', 'true')
363→                    desktopToggle.setAttribute('aria-expanded', 'false')
364→                }
365→
366→                desktopToggle.addEventListener('click', () => {
367→                    const isOpen = newsletterPanel.getAttribute('aria-hidden') === 'false'
368→                    if (isOpen) closeNewsletter()
369→                    else openNewsletter()
370→                })
371→
372→                document.addEventListener('keydown', (e: KeyboardEvent) => {
373→                    if (e.key === 'Escape' && newsletterPanel.getAttribute('aria-hidden') === 'false') {
374→                        closeNewsletter()
375→                        desktopToggle.focus()
376→                    }
377→                })
378→            }
379→        }
380→
381→        // Mobile menu
382→        const menuToggle = document.querySelector<HTMLButtonElement>('[data-mobile-menu-toggle]')
383→        const mobileMenu = document.getElementById('mobile-menu')
384→
385→        if (!menuToggle || !mobileMenu) return
386→        if (menuToggle.dataset.bound) return
387→        menuToggle.dataset.bound = 'true'
388→
389→        const openMobileMenu = () => {
390→            mobileMenu.removeAttribute('inert')
391→            menuToggle.setAttribute('aria-expanded', 'true')
392→            menuToggle.setAttribute('aria-label', 'Close menu')
393→            // Focus first link after animation starts
394→            const firstLink = mobileMenu.querySelector<HTMLElement>('[data-mobile-nav-link]')
395→            setTimeout(() => firstLink?.focus(), 50)
396→        }
397→
398→        const closeMobileMenu = () => {
399→            mobileMenu.setAttribute('inert', '')
400→            menuToggle.setAttribute('aria-expanded', 'false')
401→            menuToggle.setAttribute('aria-label', 'Open menu')
402→        }
403→
404→        menuToggle.addEventListener('click', () => {
405→            const isOpen = !mobileMenu.hasAttribute('inert')
406→            if (isOpen) closeMobileMenu()
407→            else openMobileMenu()
408→        })
409→
410→        // Close on nav link click
411→        mobileMenu.querySelectorAll('[data-mobile-nav-link]').forEach((link) => {
412→            link.addEventListener('click', () => closeMobileMenu())
413→        })
414→
415→        // Close on Escape
416→        document.addEventListener('keydown', (e: KeyboardEvent) => {
417→            if (e.key === 'Escape' && !mobileMenu.hasAttribute('inert')) {
418→                closeMobileMenu()
419→                menuToggle.focus()
420→            }
421→        })
422→
423→        // Close on outside click
424→        document.addEventListener('click', (e: MouseEvent) => {
425→            if (!mobileMenu.hasAttribute('inert')) {
426→                const header = menuToggle.closest('header')
427→                if (header && !header.contains(e.target as Node)) {
428→                    closeMobileMenu()
429→                }
430→            }
431→        })
432→    })
433→</script>
