$reverseClass: ".theme-toggle--reversed";
// The selector used to disabled prefers motion
$forceMotionClass: ".theme-toggle--force-motion";
// Total duration of each animation
$duration: 500ms;

// Change which elements we generate styles for
$button: true !default;
$div: true !default;
$checkbox: false !default;

