---
import { ClientRouter } from 'astro:transitions'

interface Props {
    title: string
    description?: string
    ogImage?: string
    /** Force dark mode regardless of system preference (used by landing page) */
    forceDark?: boolean
}

const {
    title,
    description = 'The fastest two-pane file manager for macOS. Indexes your entire drive in minutes — directory sizes, instant search, keyboard-driven everything. Built in Rust, free for personal use.',
    ogImage,
    forceDark = false,
} = Astro.props
---

<!doctype html>
<html lang="en" {...forceDark ? { 'data-force-dark': '' } : {}}>
    <head>
        <ClientRouter />
        <meta charset="UTF-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1.0" />
        <meta name="description" content={description} />
        {
            forceDark ? (
                <>
                    <meta name="theme-color" content="#14130f" />
                    <meta name="color-scheme" content="dark" />
                </>
            ) : (
                <>
                    <meta name="theme-color" content="#14130f" media="(prefers-color-scheme: dark)" />
                    <meta name="theme-color" content="#fafaf8" media="(prefers-color-scheme: light)" />
                    <meta name="color-scheme" content="dark light" />
                </>
            )
        }

        <!-- Open Graph -->
        <meta property="og:title" content={title} />
        <meta property="og:description" content={description} />
        <meta property="og:type" content="website" />
        <meta property="og:url" content={Astro.url.href} />
        {ogImage && <meta property="og:image" content={new URL(ogImage, Astro.site).href} />}

        <!-- Twitter -->
        <meta name="twitter:card" content="summary_large_image" />
        <meta name="twitter:title" content={title} />
        <meta name="twitter:description" content={description} />
        {ogImage && <meta name="twitter:image" content={new URL(ogImage, Astro.site).href} />}

        <!-- Favicon -->
        <link rel="icon" href="/favicon.ico" sizes="32x32" />
        <link rel="icon" type="image/png" sizes="64x64" href="/favicon.png" />
        <link rel="apple-touch-icon" href="/apple-touch-icon.png" />

        <!-- RSS autodiscovery -->
        <link rel="alternate" type="application/rss+xml" title="Cmdr blog" href="/rss.xml" />

        <!-- Preload self-hosted font for faster FCP -->
        <link rel="preload" as="font" type="font/woff2" href="/fonts/inter-latin-variable.woff2" crossorigin />

        <title>{title}</title>

        <!-- Organization structured data -->
        <script
            type="application/ld+json"
            set:html={JSON.stringify({
                '@context': 'https://schema.org',
                '@type': 'Organization',
                name: 'Cmdr',
                url: 'https://getcmdr.com',
                logo: 'https://getcmdr.com/logo-512.png',
                sameAs: ['https://github.com/vdavid/cmdr'],
            })}
        />

        {/* Prevent light-mode FOUC: set background before first paint */}
        <style is:inline>
            @media (prefers-color-scheme: light) {
                html:not([data-force-dark]) {
                    background-color: #fafaf8;
                }
            }
        </style>

        {/* Hide newsletter icon before first paint if user already subscribed/dismissed */}
        <script is:inline>
            try {
                if (
                    localStorage.getItem('newsletter-subscribed') === 'true' ||
                    localStorage.getItem('newsletter-dismissed') === 'true' ||
                    localStorage.getItem('newsletter-cta-dismissed') === 'true'
                ) {
                    document.documentElement.classList.add('newsletter-hidden')
                }
            } catch (e) {}
        </script>

        {/* Umami analytics — self-hosted, cookieless */}
        {
            import.meta.env.PUBLIC_UMAMI_WEBSITE_ID && (
                <script
                    defer
                    src={`${import.meta.env.PUBLIC_UMAMI_HOST}/mami`}
                    data-website-id={import.meta.env.PUBLIC_UMAMI_WEBSITE_ID}
                />
            )
        }
    </head>
    <body class="min-h-screen">
        <slot />

        {
            /* PostHog — session replay, heatmaps, click tracking.
            Loaded from PostHog's CDN to avoid bundling dompurify (has an unpatched XSS advisory).
            Snippet lives in public/scripts/posthog-init.js (extracted to avoid prettier parse errors). */
        }
        {
            import.meta.env.PUBLIC_POSTHOG_KEY && (
                <script
                    is:inline
                    src="/scripts/posthog-init.js"
                    data-ph-key={import.meta.env.PUBLIC_POSTHOG_KEY}
                    data-ph-host={import.meta.env.PUBLIC_POSTHOG_HOST || 'https://eu.i.posthog.com'}
                />
            )
        }

        <script is:inline>
            ;(function () {
                function applyArch(arch) {
                    document.querySelectorAll('a[data-download-link]').forEach(function (el) {
                        var url = arch === 'aarch64' ? el.dataset.dmgArm : el.dataset.dmgIntel
                        if (url) el.href = url
                        el.dataset.umamiEventArch = arch
                        var size = arch === 'aarch64' ? el.dataset.sizeArm : el.dataset.sizeIntel
                        if (size) {
                            el.querySelectorAll('[data-download-size]').forEach(function (s) {
                                s.textContent = s.textContent.replace(/\d+ MB/, size)
                            })
                        }
                    })
                    document.querySelectorAll('[data-download-dropdown] [data-arch]').forEach(function (el) {
                        if (el.dataset.arch === arch) {
                            el.dataset.recommended = 'true'
                        }
                    })
                }

                // Detect arch synchronously to avoid flash of universal binary on first paint.
                // WebGL renderer reports "Apple M1/M2/GPU" on Apple Silicon, "Intel/AMD" on Intel Macs.
                // Falls back to localStorage cache from a previous async detection.
                function detectArchSync() {
                    try {
                        var canvas = document.createElement('canvas')
                        var gl = canvas.getContext('webgl')
                        if (!gl) return null
                        var ext = gl.getExtension('WEBGL_debug_renderer_info')
                        if (!ext) return null
                        var renderer = gl.getParameter(ext.UNMASKED_RENDERER_WEBGL)
                        if (/Apple M|Apple GPU/.test(renderer)) return 'aarch64'
                        if (/Intel|AMD/.test(renderer)) return 'x86_64'
                    } catch (e) {}
                    return null
                }

                var syncArch = detectArchSync()
                if (!syncArch) {
                    try {
                        syncArch = localStorage.getItem('cmdr-arch')
                    } catch (e) {
                        /* localStorage unavailable */
                    }
                }
                if (syncArch) applyArch(syncArch)

                // Detect arch async and update cache for next visit
                if (!navigator.userAgentData) return
                navigator.userAgentData
                    .getHighEntropyValues(['architecture'])
                    .then(function (ua) {
                        var arch = ua.architecture === 'arm' ? 'aarch64' : ua.architecture === 'x86' ? 'x86_64' : null
                        if (!arch) return
                        try {
                            localStorage.setItem('cmdr-arch', arch)
                        } catch (e) {
                            /* localStorage unavailable */
                        }
                        applyArch(arch)
                    })
                    .catch(function () {})
            })()
        </script>
    </body>
</html>

<style is:global>
    @import '../styles/global.css';
</style>

