<style>
    /* Text blur-in animation - global so it applies to classes */
    :global(.animate-blur-in) {
        animation: blur-in 1s cubic-bezier(0.16, 1, 0.3, 1) both;
    }

    /* Stagger delays for 7-step animation (100ms apart, overlapping) */
    :global(.stagger-1) {
        animation-delay: 0ms;
    }
    :global(.stagger-2) {
        animation-delay: 100ms;
    }
    :global(.stagger-3) {
        animation-delay: 200ms;
    }
    :global(.stagger-4) {
        animation-delay: 300ms;
    }
    :global(.stagger-5) {
        animation-delay: 400ms;
    }
    :global(.stagger-6) {
        animation-delay: 500ms;
    }
    :global(.stagger-7) {
        animation-delay: 600ms;
    }

    @keyframes blur-in {
        from {
            opacity: 0;
            filter: blur(10px);
            transform: translateY(10px);
        }
        to {
            opacity: 1;
            filter: blur(0);
            transform: translateY(0);
        }
    }

    .hero-section {
        min-height: 100vh;
        position: relative;
    }

    /* Gradient overlay at bottom - covers full width including padding */
    .hero-section::after {
        content: '';
        pointer-events: none;
        z-index: 5;
        background: linear-gradient(to bottom, transparent 50%, var(--color-background) 100%);
        position: absolute;
        inset: 0;
    }

    .hero-content {
        position: relative;
        z-index: 10;
    }

    .hero-illustration {
        pointer-events: none;
        user-select: none;
        width: 100%;
        position: relative;
        margin-top: -200px;
        margin-left: -100px;
    }

    @media (max-width: 767px) {
        .hero-illustration {
            height: 600px;
            margin-top: 0;
            margin-left: -40px;
        }
    }

    .hero-perspective {
        perspective: 4000px;
        perspective-origin: 100% 0;
    }

    .hero-base {
        transform-origin: 0 0;
        backface-visibility: hidden;
        width: 1600px;
        height: 900px;
        margin: 280px auto auto;
        position: absolute;
        top: 0;
        bottom: 0;
        left: -100px;
        right: 0;
        transform: translate(2%) scale(1.2) rotateX(47deg) rotateY(31deg) rotate(324deg);
    }

    @media (max-width: 767px) {
        .hero-base {
            margin-top: 100px;
            margin-left: 1%;
            transform: scale(0.7) rotateX(47deg) rotateY(21deg) rotate(330deg);
        }
    }

    /* Scale hero image on large screens */
    @media (min-width: 1700px) {
        .hero-base {
            width: 94vw;
            height: calc(94vw * 9 / 16);
        }
    }

    .hero-layer {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        object-fit: contain;
    }

    /* Gradient fade on right edge - more aggressive to avoid cutoff */
    .hero-frame,
    .hero-left-pane,
    .hero-right-pane {
        mask-image: linear-gradient(to right, black 0%, black 50%, transparent 80%);
    }

    /* Frame - visible immediately with subtle blur-in */
    .hero-frame {
        opacity: 0;
        animation: hero-image-in 1.5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    }

    /* Right pane - animates in first (blur + translate) */
    .hero-right-pane {
        opacity: 0;
        animation: hero-image-in 2s cubic-bezier(0.16, 1, 0.3, 1) 0.3s forwards;
    }

    /* Left pane - animates in second */
    .hero-left-pane {
        opacity: 0;
        animation: hero-image-in 2s cubic-bezier(0.16, 1, 0.3, 1) 1s forwards;
    }

    @keyframes hero-image-in {
        0% {
            opacity: 0;
            filter: blur(10px);
            transform: translate(165%, 200%);
        }
        100% {
            opacity: 1;
            filter: none;
            transform: none;
        }
    }

    /* Degrade to opacity-only fade under reduced motion */
    @keyframes fade-in-only {
        from {
            opacity: 0;
        }
        to {
            opacity: 1;
        }
    }

    @media (prefers-reduced-motion: reduce) {
        :global(.animate-blur-in) {
            animation: fade-in-only 0.5s ease both;
            filter: none;
            transform: none;
        }

        .hero-frame,
        .hero-right-pane,
        .hero-left-pane {
            animation: fade-in-only 0.8s ease both;
            filter: none;
            transform: none;
        }
    }
</style>

