        align-items: center;
        padding: 12px 16px;
        font-size: 0.9375rem;
        color: var(--color-text-secondary);
        text-decoration: none;
        border-radius: 0.5rem;
        min-height: 44px;
        transition:
            background-color var(--duration-normal),
            color var(--duration-normal);
