    { href: '/pricing', label: 'Pricing' },
    { href: '/blog', label: 'Blog' },
    { href: '/changelog', label: 'Changelog' },
    { href: '/roadmap', label: 'Roadmap' },
    { href: 'https://github.com/vdavid/cmdr', label: 'GitHub', external: true },
]
---

<header
    class="fixed top-0 left-0 right-0 z-50 border-b border-[var(--color-border-subtle)] bg-[var(--color-background)]/80 backdrop-blur-xl"
    transition:persist
>
    <nav class="mx-auto flex h-16 max-w-6xl items-center justify-between px-6">
        <!-- Logo -->
        <a
            href="/"
            class="flex items-center gap-2 text-xl font-semibold transition-opacity hover:opacity-80"
            aria-label="Cmdr home"
        >
            <img src="/logo-32.png" alt="" width="32" height="32" class="h-6 w-6" />
            <span>Cmdr</span>
        </a>

        <!-- Desktop navigation -->
        <div class="hidden items-center gap-8 md:flex">
            {
                navLinks.map((link) => (
                    <a
                        href={link.href}
                        target={link.external ? '_blank' : undefined}
                        rel={link.external ? 'noopener noreferrer' : undefined}
                        class="text-sm text-[var(--color-text-secondary)] transition-colors duration-200 hover:text-[var(--color-text-primary)]"
                    >
                        {link.label}
                        {link.external && (
                            <span class="ml-1 text-xs" aria-hidden="true">
                                ↗
                            </span>
                        )}
                    </a>
                ))
            }

            <!-- Newsletter toggle (desktop) -->
            <button
                type="button"
                class="newsletter-toggle cursor-pointer text-[var(--color-text-secondary)] transition-colors duration-200 hover:text-[var(--color-text-primary)]"
                aria-expanded="false"
                aria-controls="newsletter-panel"
                aria-label="Newsletter"
                title="Newsletter"
                data-newsletter-toggle
                data-newsletter-nav
            >
                <svg
                    class="h-4 w-4"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                    stroke-width="1.5"
                    aria-hidden="true"
                >
                    <path
                        stroke-linecap="round"
                        stroke-linejoin="round"
                        d="M21.75 6.75v10.5a2.25 2.25 0 0 1-2.25 2.25h-15a2.25 2.25 0 0 1-2.25-2.25V6.75m19.5 0A2.25 2.25 0 0 0 19.5 4.5h-15a2.25 2.25 0 0 0-2.25 2.25m19.5 0v.243a2.25 2.25 0 0 1-1.07 1.916l-7.5 4.615a2.25 2.25 0 0 1-2.36 0L3.32 8.91a2.25 2.25 0 0 1-1.07-1.916V6.75"
                    ></path>
                </svg>
            </button>

            <!-- Theme toggle (desktop) -->
            <ThemeToggle />

            <!-- CTA Button -->
            <DownloadButton variant="header" />
        </div>

        <!-- Theme toggle + hamburger (mobile) -->
        <div class="flex items-center md:hidden">
            <ThemeToggle />
            <button
                type="button"
                class="mobile-menu-toggle flex items-center justify-center"
                aria-label="Open menu"
                aria-expanded="false"
                aria-controls="mobile-menu"
                data-mobile-menu-toggle
            >
            <svg
                class="hamburger-icon"
                width="24"
                height="24"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                stroke-linecap="round"
                stroke-linejoin="round"
                aria-hidden="true"
            >
                <line class="hamburger-line hamburger-line--top" x1="3" y1="6" x2="21" y2="6"></line>
                <line class="hamburger-line hamburger-line--middle" x1="3" y1="12" x2="21" y2="12"></line>
                <line class="hamburger-line hamburger-line--bottom" x1="3" y1="18" x2="21" y2="18"></line>
            </svg>
        </button>
    </nav>

    <!-- Mobile menu -->
    <div id="mobile-menu" class="mobile-menu md:hidden" inert role="navigation" aria-label="Mobile navigation">
        <div class="mobile-menu__content">
            {
                navLinks.map((link) => (
                    <a
                        href={link.href}
                        target={link.external ? '_blank' : undefined}
                        rel={link.external ? 'noopener noreferrer' : undefined}
                        class="mobile-menu__link"
                        data-mobile-nav-link
                    >
                        {link.label}
                        {link.external && (
                            <span class="ml-1 text-xs" aria-hidden="true">
                                ↗
                            </span>
                        )}
                    </a>
                ))
            }

            <!-- Download CTA (mobile) -->
            <div class="mt-2" data-mobile-nav-link>
                <DownloadButton variant="mobile" class="w-full" />
            </div>

            <!-- Newsletter section (mobile) -->
            <div class="mobile-menu__newsletter" data-newsletter-nav>
                <p class="mobile-menu__newsletter-label">Newsletter</p>
                <p class="mobile-menu__newsletter-desc">Get Cmdr news in your inbox. No spam, promise.</p>
                <NewsletterForm variant="inline" />
            </div>
        </div>
    </div>

    <!-- Newsletter slide-open panel (desktop) -->
    <div id="newsletter-panel" class="newsletter-panel hidden md:block" aria-hidden="true">
        <div class="mx-auto flex max-w-2xl flex-col items-center gap-3 px-6 py-5">
            <p class="text-sm text-[var(--color-text-secondary)]">
                How cool that you want to hear about Cmdr news! I promise not to spam you. ❤️
            </p>
            <div class="w-full max-w-md">
                <NewsletterForm variant="inline" />
            </div>
        </div>
    </div>
</header>

<style>
    /* Newsletter icon toggle (desktop) */
    .newsletter-toggle {
        display: flex;
        align-items: center;
        justify-content: center;
        padding: 6px;
        background: none;
        border: 1px solid transparent;
        border-radius: 0.375rem;
        transition:
            color var(--duration-normal),
            border-color var(--duration-normal);
    }

    .newsletter-toggle:hover {
        border-color: var(--color-border-subtle);
    }

    .newsletter-toggle:focus-visible {
        outline: 2px solid var(--color-accent);
        outline-offset: 2px;
    }

    /* Hamburger button */
    .mobile-menu-toggle {
        width: 44px;
        height: 44px;
        padding: 10px;
        color: var(--color-text-primary);
        background: none;
        border: none;
        cursor: pointer;
        border-radius: 0.5rem;
        transition: background-color var(--duration-normal);
    }

    .mobile-menu-toggle:hover {
        background-color: var(--color-surface-elevated);
    }

    .mobile-menu-toggle:focus-visible {
        outline: 2px solid var(--color-accent);
        outline-offset: 2px;
    }

    /* Hamburger line animations */
    .hamburger-line {
        transition:
            transform var(--duration-normal) var(--ease-out-expo),
            opacity var(--duration-normal) var(--ease-out-expo);
        transform-box: fill-box;
        transform-origin: center;
    }

    .mobile-menu-toggle[aria-expanded='true'] .hamburger-line--top {
        transform: translateY(6px) rotate(45deg);
    }

    .mobile-menu-toggle[aria-expanded='true'] .hamburger-line--middle {
        opacity: 0;
    }

    .mobile-menu-toggle[aria-expanded='true'] .hamburger-line--bottom {
        transform: translateY(-6px) rotate(-45deg);
    }

    /* Mobile menu */
    .mobile-menu {
        max-height: 0;
        overflow: hidden;
        border-top: 1px solid transparent;
        visibility: hidden;
        transition:
            max-height var(--duration-slow) var(--ease-out-expo),
            visibility 0s var(--duration-slow);
    }

    .mobile-menu:not([inert]) {
        max-height: 600px;
        border-top-color: var(--color-border-subtle);
        visibility: visible;
        transition:
            max-height var(--duration-slow) var(--ease-out-expo),
            visibility 0s;
    }

    .mobile-menu__content {
        display: flex;
        flex-direction: column;
        padding: 8px 24px 24px;
        gap: 4px;
    }

    .mobile-menu__link {
        display: flex;
        align-items: center;
        padding: 12px 16px;
        font-size: 0.9375rem;
        color: var(--color-text-secondary);
        text-decoration: none;
        border-radius: 0.5rem;
        min-height: 44px;
        transition:
            background-color var(--duration-normal),
            color var(--duration-normal);
    }

    .mobile-menu__link:hover {
        background-color: var(--color-surface-elevated);
        color: var(--color-text-primary);
    }

    .mobile-menu__link:focus-visible {
        outline: 2px solid var(--color-accent);
        outline-offset: -2px;
    }

    .mobile-menu__newsletter {
        margin-top: 12px;
        padding: 16px;
        border-radius: 0.5rem;
        background: var(--color-surface);
        border: 1px solid var(--color-border-subtle);
    }

    .mobile-menu__newsletter-label {
        font-size: 0.8125rem;
        font-weight: 600;
        color: var(--color-text-primary);
        margin: 0 0 4px;
    }

    .mobile-menu__newsletter-desc {
        font-size: 0.8125rem;
        color: var(--color-text-tertiary);
        margin: 0 0 12px;
    }

    /* Desktop newsletter panel */
    .newsletter-panel {
        max-height: 0;
        overflow: hidden;
        visibility: hidden;
        transition:
            max-height var(--duration-slow) var(--ease-out-expo),
            visibility 0s var(--duration-slow);
        border-top: 1px solid transparent;
    }

    .newsletter-panel[aria-hidden='false'] {
        max-height: 200px;
        border-top-color: var(--color-border-subtle);
        visibility: visible;
        transition:
            max-height var(--duration-slow) var(--ease-out-expo),
            visibility 0s;
    }

    @media (prefers-reduced-motion: reduce) {
        .mobile-menu,
        .newsletter-panel,
        .hamburger-line {
            transition: none !important;
        }
    }
</style>

<script>
    document.addEventListener('astro:page-load', () => {
        // Check if newsletter should be hidden site-wide
        const newsletterHidden =
            localStorage.getItem('newsletter-subscribed') === 'true' ||
            localStorage.getItem('newsletter-dismissed') === 'true' ||
            localStorage.getItem('newsletter-cta-dismissed') === 'true'

        // Desktop newsletter toggle
        const desktopToggle = document.querySelector<HTMLButtonElement>('[data-newsletter-toggle]')
        const newsletterPanel = document.getElementById('newsletter-panel')

        if (newsletterHidden) {
            // Hide all newsletter nav elements
            document.querySelectorAll<HTMLElement>('[data-newsletter-nav]').forEach((el) => {
                el.style.display = 'none'
            })
            // Close the panel if it's open
            if (newsletterPanel && newsletterPanel.getAttribute('aria-hidden') === 'false') {
                newsletterPanel.setAttribute('aria-hidden', 'true')
                if (desktopToggle) desktopToggle.setAttribute('aria-expanded', 'false')
            }
        }

        if (desktopToggle && newsletterPanel && !newsletterHidden) {
            if (!desktopToggle.dataset.bound) {
                desktopToggle.dataset.bound = 'true'

                const openNewsletter = () => {
                    newsletterPanel.setAttribute('aria-hidden', 'false')
                    desktopToggle.setAttribute('aria-expanded', 'true')
                    const emailInput = newsletterPanel.querySelector<HTMLInputElement>('input[type="email"]')
                    setTimeout(() => emailInput?.focus(), 50)
                }

                const closeNewsletter = () => {
                    newsletterPanel.setAttribute('aria-hidden', 'true')
                    desktopToggle.setAttribute('aria-expanded', 'false')
                }

                desktopToggle.addEventListener('click', () => {
                    const isOpen = newsletterPanel.getAttribute('aria-hidden') === 'false'
                    if (isOpen) closeNewsletter()
                    else openNewsletter()
                })

                document.addEventListener('keydown', (e: KeyboardEvent) => {
                    if (e.key === 'Escape' && newsletterPanel.getAttribute('aria-hidden') === 'false') {
                        closeNewsletter()
                        desktopToggle.focus()
                    }
                })
            }
        }

        // Mobile menu
        const menuToggle = document.querySelector<HTMLButtonElement>('[data-mobile-menu-toggle]')
        const mobileMenu = document.getElementById('mobile-menu')

        if (!menuToggle || !mobileMenu) return
        if (menuToggle.dataset.bound) return
        menuToggle.dataset.bound = 'true'

        const openMobileMenu = () => {
            mobileMenu.removeAttribute('inert')
            menuToggle.setAttribute('aria-expanded', 'true')
            menuToggle.setAttribute('aria-label', 'Close menu')
            // Focus first link after animation starts
            const firstLink = mobileMenu.querySelector<HTMLElement>('[data-mobile-nav-link]')
            setTimeout(() => firstLink?.focus(), 50)
        }

        const closeMobileMenu = () => {
            mobileMenu.setAttribute('inert', '')
            menuToggle.setAttribute('aria-expanded', 'false')
            menuToggle.setAttribute('aria-label', 'Open menu')
        }

        menuToggle.addEventListener('click', () => {
            const isOpen = !mobileMenu.hasAttribute('inert')
            if (isOpen) closeMobileMenu()
            else openMobileMenu()
        })

        // Close on nav link click
        mobileMenu.querySelectorAll('[data-mobile-nav-link]').forEach((link) => {
            link.addEventListener('click', () => closeMobileMenu())
        })

        // Close on Escape
        document.addEventListener('keydown', (e: KeyboardEvent) => {
            if (e.key === 'Escape' && !mobileMenu.hasAttribute('inert')) {
                closeMobileMenu()
                menuToggle.focus()
            }
        })

        // Close on outside click
        document.addEventListener('click', (e: MouseEvent) => {
            if (!mobileMenu.hasAttribute('inert')) {
                const header = menuToggle.closest('header')
                if (header && !header.contains(e.target as Node)) {
                    closeMobileMenu()
                }
            }
        })
    })
</script>

