/**
 * Animated sun/moon theme toggle.
 * Based on the "within" toggle from theme-toggles by Alfred Jones.
 * MIT License / Copyright (c) 2021 Alfred Jones
 * https://github.com/AlfieJones/theme-toggles
 */
---

<button
    type="button"
    class="theme-toggle"
    aria-label="Switch theme"
    title="Switch theme"
    data-theme-toggle
>
    <svg
        class="theme-toggle__within"
        width="1em"
        height="1em"
        fill="currentColor"
        viewBox="0 0 32 32"
        aria-hidden="true"
    >
        <clipPath id="theme-toggle__within__clip">
            <path d="M0 0h32v32h-32ZM6 16A1 1 0 0026 16 1 1 0 006 16" />
        </clipPath>
        <g clip-path="url(#theme-toggle__within__clip)">
            <path
                d="M30.7 21.3 27.1 16l3.7-5.3c.4-.5.1-1.3-.6-1.4l-6.3-1.1-1.1-6.3c-.1-.6-.8-.9-1.4-.6L16 5l-5.4-3.7c-.5-.4-1.3-.1-1.4.6l-1 6.3-6.4 1.1c-.6.1-.9.9-.6 1.3L4.9 16l-3.7 5.3c-.4.5-.1 1.3.6 1.4l6.3 1.1 1.1 6.3c.1.6.8.9 1.4.6l5.3-3.7 5.3 3.7c.5.4 1.3.1 1.4-.6l1.1-6.3 6.3-1.1c.8-.1 1.1-.8.7-1.4zM16 25.1c-5.1 0-9.1-4.1-9.1-9.1 0-5.1 4.1-9.1 9.1-9.1s9.1 4.1 9.1 9.1c0 5.1-4 9.1-9.1 9.1z"
            ></path>
        </g>
        <path
            class="theme-toggle__within__circle"
            d="M16 7.7c-4.6 0-8.2 3.7-8.2 8.2s3.6 8.4 8.2 8.4 8.2-3.7 8.2-8.2-3.6-8.4-8.2-8.4zm0 14.4c-3.4 0-6.1-2.9-6.1-6.2s2.7-6.1 6.1-6.1c3.4 0 6.1 2.9 6.1 6.2s-2.7 6.1-6.1 6.1z"
        ></path>
        <path
            class="theme-toggle__within__inner"
            d="M16 9.5c-3.6 0-6.4 2.9-6.4 6.4s2.8 6.5 6.4 6.5 6.4-2.9 6.4-6.4-2.8-6.5-6.4-6.5z"
        ></path>
    </svg>
</button>

<style>
    .theme-toggle {
        display: flex;
        align-items: center;
        justify-content: center;
        padding: 6px;
        font-size: 1rem;
        color: var(--color-text-secondary);
        background: none;
        border: 1px solid transparent;
        border-radius: 0.375rem;
        cursor: pointer;
        transition:
            color var(--duration-normal),
            border-color var(--duration-normal);
    }

    .theme-toggle:hover {
        color: var(--color-text-primary);
        border-color: var(--color-border-subtle);
    }

    .theme-toggle:focus-visible {
        outline: 2px solid var(--color-accent);
        outline-offset: 2px;
    }

    /* Toggle animation — only after first paint to prevent entrance animation */
    .theme-toggle[data-ready] .theme-toggle__within * {
        transform-origin: center;
        transition: transform 500ms cubic-bezier(0, 0, 0, 1.25);
    }

    /* Dark (toggled) state: explicit data-theme */
    :global(:root[data-theme='dark']) .theme-toggle__within__circle {
        transform: scale(1.5);
    }
    :global(:root[data-theme='dark']) .theme-toggle__within__inner {
        transform: translate3d(3px, -3px, 0) scale(1.2);
    }
    :global(:root[data-theme='dark']) .theme-toggle__within g path {
        transform: scale(0.65);
    }

    /* Dark (toggled) state: system preference fallback (no explicit theme) */
    @media (prefers-color-scheme: dark) {
        :global(:root:not([data-theme='light'])) .theme-toggle__within__circle {
            transform: scale(1.5);
        }
        :global(:root:not([data-theme='light'])) .theme-toggle__within__inner {
            transform: translate3d(3px, -3px, 0) scale(1.2);
        }
        :global(:root:not([data-theme='light'])) .theme-toggle__within g path {
            transform: scale(0.65);
        }
    }

    @media (prefers-reduced-motion: reduce) {
        .theme-toggle[data-ready] .theme-toggle__within * {
            transition: none;
        }
    }
</style>

<script>
    document.addEventListener('astro:page-load', () => {
        const toggle = document.querySelector<HTMLButtonElement>('[data-theme-toggle]')
        if (!toggle || toggle.dataset.bound) return
        toggle.dataset.bound = ''

        // Enable transitions after first frame (prevents entrance animation)
        requestAnimationFrame(() => {
            toggle.dataset.ready = ''
        })

        toggle.addEventListener('click', () => {
            const current =
                document.documentElement.dataset.theme ||
                (window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark')
            const next = current === 'light' ? 'dark' : 'light'
            document.documentElement.dataset.theme = next
            try {
                localStorage.setItem('theme', next)
            } catch {
                /* localStorage unavailable */
            }

            // Update meta theme-color to match
            document
                .querySelectorAll<HTMLMetaElement>('meta[name="theme-color"]')
                .forEach((meta) => {
                    meta.content = next === 'light' ? '#fafaf8' : '#14130f'
                    meta.removeAttribute('media')
                })
        })
    })
</script>

